import React from 'react';

const Home = () => (
  <section className="bg-cafe-texture bg-cover bg-center py-20 text-center px-4">
  <h1 className="text-4xl font-bold text-brand mb-4">Welcome to Ila Café & Desserts</h1>
  <p className="text-gray-700 max-w-2xl mx-auto">
    Serving irresistible waffles, dreamy desserts, and refreshing drinks in the heart of London.
  </p>
</section>
);


export default Home;
